+/// Wraps an identifier with backticks, escaping embedded backticks.
+auto quote_identifier(std::string_view name) -> std::string {
+  auto result = std::string{"`"};
+  for (auto c : name) {
+    if (c == '`') {
+      result += "``";
+    } else {
+      result += c;
+    }
+  }
+  result += '`';
+  return result;
+}
